t.script:
document.addEventListener('DOMContentLoaded', function () {
    const methodSelect = document.getElementById('payment_method');
    const bankContainer = document.getElementById('bank_journal_container');
    const confirmBtn = document.getElementById('confirm_payment_btn');
    const form = document.getElementById('step3_form');

    let actionHidden = document.getElementById('action_hidden');
    if (form && !actionHidden) {
        actionHidden = document.createElement('input');
        actionHidden.type = 'hidden';
        actionHidden.name = 'action';
        actionHidden.id = 'action_hidden';
        form.appendChild(actionHidden);
    }

    const amountInput = document.querySelector('input[name="amount"]');
    const journalSelect = document.querySelector('select[name="journal_id"]');

    if (methodSelect) {
        methodSelect.addEventListener('change', function() {
            if (bankContainer) {
                bankContainer.style.display = (methodSelect.value === 'bank') ? 'block' : 'none';
            }
        });
    }

    if (confirmBtn) {
        confirmBtn.addEventListener('click', function (event) {
            event.preventDefault();

            if (amountInput && !amountInput.readOnly && (!amountInput.value || parseFloat(amountInput.value) <= 0)) {
                alert("يرجى إدخال مبلغ صحيح.");
                return;
            }
            if (methodSelect && methodSelect.value === 'selected') {
                alert("يرجى اختيار طريقة الدفع.");
                return;
            }
            if (methodSelect && methodSelect.value === 'bank' && (!journalSelect || !journalSelect.value)) {
                alert("يرجى اختيار البنك.");
                return;
            }

            if (confirm("عزيزي العميل، عند تأكيد الدفع سيتم إنشاء سند دفع مبدئي. هل ترغب بالمتابعة؟")) {
                confirmBtn.disabled = true;
                confirmBtn.innerText = 'جاري المعالجة والترحيل المالي...';
                if (actionHidden) { actionHidden.value = 'confirm'; }
                if (form) { form.submit(); }
            }
        });
    }
});
